        '<div style="display:flex;align-items:center;justify-content:center;height:100%;color:#606070;font-family:Inter,sans-serif;font-size:14px">No data available</div>';
    } else {
      const chart = createChart(m7Container, {
        layout: { background: { color: 'transparent' }, textColor: CHART_COLORS.textColor },
        grid: {
          vertLines: { color: CHART_COLORS.gridLinesColor },
          horzLines: { color: CHART_COLORS.gridLinesColor },
        },
        rightPriceScale: { borderVisible: false },
        timeScale: { borderVisible: false, timeVisible: false },
        handleScroll: false,
        handleScale: false,
        autoSize: true,
      });
      const series = chart.addSeries(LineSeries, {
        color: '#22c55e',
        lineWidth: 2,
        pointMarkersVisible: true,
      });
      series.setData(rawSeries);
      chart.timeScale().fitContent();
    }
  }

  // Metric 8 — bar chart
  const m8Canvas = document.getElementById('metric-8') as HTMLCanvasElement | null;
  if (m8Canvas) {
    const labels: string[] = JSON.parse(m8Canvas.dataset.labels ?? '[]');
    const values: number[] = JSON.parse(m8Canvas.dataset.values ?? '[]');
    if (!values.length) {
      m8Canvas.parentElement!.innerHTML =
        '<div style="display:flex;align-items:center;justify-content:center;height:100%;color:#606070;font-family:Inter,sans-serif;font-size:14px">No data available</div>';
    } else {
      new Chart(m8Canvas, {
        type: 'bar',
        data: {
          labels,
          datasets: [{ data: values, backgroundColor: '#8b5cf6', borderRadius: 3 }],
        },
        options: DARK_CHART_OPTIONS,
      });
    }
  }

  // Metric 9 — doughnut
  const m9Canvas = document.getElementById('metric-9') as HTMLCanvasElement | null;
  if (m9Canvas) {
    const labels: string[] = JSON.parse(m9Canvas.dataset.labels ?? '[]');
    const values: number[] = JSON.parse(m9Canvas.dataset.values ?? '[]');
    const colors: string[] = JSON.parse(m9Canvas.dataset.colors ?? '[]');
    if (!values.length) {
      m9Canvas.parentElement!.innerHTML =
        '<div style="display:flex;align-items:center;justify-content:center;height:100%;color:#606070;font-family:Inter,sans-serif;font-size:14px">No data available</div>';
    } else {
      new Chart(m9Canvas, {
        type: 'doughnut',
        data: { labels, datasets: [{ data: values, backgroundColor: colors, borderWidth: 0 }] },
        options: {
