              ...DARK_CHART_OPTIONS.scales.y,
              title: { display: true, text: 'Agent %', color: '#606070', font: { family: 'Inter', size: 10 } },
            },
          },
        },
      });
    }
  }

  // Metric 19 — bar chart (cadence)
  const m19Canvas = document.getElementById('metric-19') as HTMLCanvasElement | null;
  if (m19Canvas) {
    const labels: string[] = JSON.parse(m19Canvas.dataset.labels ?? '[]');
    const values: number[] = JSON.parse(m19Canvas.dataset.values ?? '[]');
    if (!values.length) {
      m19Canvas.parentElement!.innerHTML =
        '<div style="display:flex;align-items:center;justify-content:center;height:100%;color:#606070;font-family:Inter,sans-serif;font-size:14px">No data available</div>';
    } else {
      new Chart(m19Canvas, {
        type: 'bar',
        data: {
          labels,
          datasets: [{ data: values, backgroundColor: '#a0a0b0', borderRadius: 3 }],
        },
        options: {
          ...DARK_CHART_OPTIONS,
          plugins: {
            ...DARK_CHART_OPTIONS.plugins,
            tooltip: {
              ...DARK_CHART_OPTIONS.plugins.tooltip,
              callbacks: { label: (ctx) => ` ${ctx.parsed.y} min` },
            },
          },
        },
      });
    }
  }

  // Metric 20 — lightweight-charts line (rolling average)
  const m20Container = document.getElementById('metric-20') as HTMLDivElement | null;
  if (m20Container) {
    const rawSeries: Array<{ time: number; value: number }> = JSON.parse(
      m20Container.dataset.series ?? '[]',
    );
    if (!rawSeries.length) {
      m20Container.innerHTML =
        '<div style="display:flex;align-items:center;justify-content:center;height:100%;color:#606070;font-family:Inter,sans-serif;font-size:14px">No data available</div>';
    } else {
      const chart = createChart(m20Container, {
        layout: { background: { color: 'transparent' }, textColor: CHART_COLORS.textColor },
        grid: {
          vertLines: { color: CHART_COLORS.gridLinesColor },
          horzLines: { color: CHART_COLORS.gridLinesColor },
        },
        rightPriceScale: { borderVisible: false },
        timeScale: { borderVisible: false, timeVisible: false },
        handleScroll: false,
        handleScale: false,
        autoSize: true,
      });
      const series = chart.addSeries(LineSeries, {
        color: CHART_COLORS.lineColor,
        lineWidth: 2,
        pointMarkersVisible: true,
      });
      series.setData(rawSeries);
      chart.timeScale().fitContent();
    }
  }
</script>

